Pattern.Snippet:
```js
import { readFile } from 'node:fs/promises';
import { createServer } from 'node:http';
import { resolve } from 'node:path';

import { parseConfig } from './config.js';   // explicit .js extension
```

Anti_Pattern.Bad:
```js
// src/loader.js  (package.json has "type": "module")
const fs = require('fs');          // ← CJS in ESM project — ReferenceError at runtime
module.exports = { load };
```

Anti_Pattern.Good:
```js
// src/loader.js  (ESM project)
import { readFile } from 'node:fs/promises';
export { load };
```

Anti_Pattern.Bad:
```js
import { readFile } from 'fs/promises';
import { join } from 'path';
```

Anti_Pattern.Good:
```js
import { readFile } from 'node:fs/promises';
import { join } from 'node:path';
```
